import{_ as i,c as a,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"平台与集成: 多模型 AI 配置 | oh-my-opencode","description":"学习配置和管理多个 AI 平台（Anthropic、OpenAI、Google、Copilot），掌握自动降级机制和智能模型选择。","frontmatter":{"title":"平台与集成: 多模型 AI 配置 | oh-my-opencode","sidebarTitle":"连接你的 AI 账号","subtitle":"平台与集成: 多模型 AI 配置","description":"学习配置和管理多个 AI 平台（Anthropic、OpenAI、Google、Copilot），掌握自动降级机制和智能模型选择。","order":40},"headers":[],"relativePath":"zh/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"zh/code-yeongyu/oh-my-opencode/platforms/index.md"}'),r={name:"zh/code-yeongyu/oh-my-opencode/platforms/index.md"};function s(t,e,n,d,p,h){return o(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="平台与集成" tabindex="-1">平台与集成 <a class="header-anchor" href="#平台与集成" aria-label="Permalink to &quot;平台与集成&quot;">​</a></h1><p>本章节介绍如何配置和管理多个 AI Provider（Anthropic、OpenAI、Google、GitHub Copilot 等），以及 oh-my-opencode 的多模型自动降级机制。</p><p>通过学习本章节，你将掌握如何让系统根据任务类型和可用模型，智能选择最合适的 AI 模型，构建高效、可靠的多模型编排工作流。</p><h2 id="本章节包含" tabindex="-1">本章节包含 <a class="header-anchor" href="#本章节包含" aria-label="Permalink to &quot;本章节包含&quot;">​</a></h2><p>本章节分为两部分：</p><h3 id="_1-provider-配置" tabindex="-1">1. <a href="./provider-setup/">Provider 配置</a> <a class="header-anchor" href="#_1-provider-配置" aria-label="Permalink to &quot;1. [Provider 配置](provider-setup/)&quot;">​</a></h3><p>学习如何配置多种 AI Provider，包括：</p><ul><li>Anthropic Claude（主编排器首选）</li><li>OpenAI ChatGPT（架构审查专用）</li><li>Google Gemini（前端和媒体分析）</li><li>GitHub Copilot（备用 Provider）</li><li>Z.ai Coding Plan 和 OpenCode Zen（可选服务）</li></ul><p><strong>学完你能做什么</strong>：</p><ul><li>✅ 配置 6 种主流 AI Provider</li><li>✅ 使用交互式安装器快速设置</li><li>✅ 为不同代理指定最适合的模型</li><li>✅ 使用 <code>doctor</code> 命令诊断配置问题</li></ul><p><strong>预计时间</strong>：25-30 分钟</p><h3 id="_2-多模型策略" tabindex="-1">2. <a href="./model-resolution/">多模型策略</a> <a class="header-anchor" href="#_2-多模型策略" aria-label="Permalink to &quot;2. [多模型策略](model-resolution/)&quot;">​</a></h3><p>深入理解模型解析系统的三步优先级机制：</p><ul><li>用户覆盖（精确控制）</li><li>Provider 降级（自动容错）</li><li>系统默认（兜底方案）</li></ul><p><strong>学完你能做什么</strong>：</p><ul><li>✅ 理解模型解析的完整工作流程</li><li>✅ 根据任务需求手动指定模型</li><li>✅ 利用 Provider 降级提高系统鲁棒性</li><li>✅ 诊断和解决模型解析问题</li></ul><p><strong>预计时间</strong>：30-35 分钟</p><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><p>我们建议按以下顺序学习本章节：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[安装配置完成] --&gt; B[Provider 配置]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[多模型策略]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[进阶功能]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>为什么这个顺序？</strong></p><ol><li><strong>先配置，再理解</strong>：先学会如何配置各个 Provider，再理解背后的解析机制</li><li><strong>从简单到复杂</strong>：Provider 配置是基础操作，多模型策略是进阶概念</li><li><strong>实践验证理论</strong>：配置完 Provider 后，可以用 <code>doctor</code> 命令验证多模型策略的效果</li></ol><div class="tip custom-block"><p class="custom-block-title">快速入门路径</p><p>如果你只想快速上手，可以先完成 <a href="./provider-setup/">Provider 配置</a> 的第 1-4 步（配置基础 Provider），其他内容可以后续按需学习。</p></div><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>在学习本章节之前，请确保：</p><ul><li>✅ 已完成 <a href="./../installation/">安装和初始配置</a></li><li>✅ 安装了 OpenCode（版本 &gt;= 1.0.150）</li><li>✅ 了解基本的 JSON/JSONC 配置文件格式</li><li>✅ 拥有至少一个 AI Provider 的账号订阅（推荐 Anthropic Claude）</li></ul><div class="warning custom-block"><p class="custom-block-title">如果没有 Provider 账号怎么办？</p><p>你可以先学习配置步骤，但不实际连接 Provider。系统会使用 OpenCode 的默认模型作为兜底。</p></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details><summary><strong>我需要配置所有 Provider 吗？</strong></summary><p>不需要。你可以只配置你最常用的 Provider（比如只配置 Anthropic Claude）。oh-my-opencode 的 Provider 降级机制会自动使用可用的 Provider。</p><p>但如果你想充分利用多模型编排的优势，建议至少配置 2-3 个 Provider，这样系统可以根据任务类型自动选择最合适的模型。</p></details><details><summary><strong>Provider 配置和模型解析有什么区别？</strong></summary><ul><li><strong>Provider 配置</strong>：是&quot;安装步骤&quot;，告诉系统你有哪些 AI 服务可用</li><li><strong>模型解析</strong>：是&quot;决策逻辑&quot;，系统如何为每个代理选择使用哪个 Provider</li></ul><p>比喻：Provider 配置是&quot;招聘团队成员&quot;，模型解析是&quot;分配任务&quot;。</p></details><details><summary><strong>我可以随时修改配置吗？</strong></summary><p>可以随时修改配置文件：</p><ul><li>用户配置：<code>~/.config/opencode/oh-my-opencode.json</code></li><li>项目配置：<code>.opencode/oh-my-opencode.json</code></li></ul><p>修改后无需重启，下次使用代理时自动生效。如果修改了 Provider 认证，需要运行 <code>opencode auth login</code> 重新认证。</p></details><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章节后，你可以：</p><h3 id="推荐路径-学习-ai-代理团队" tabindex="-1">推荐路径：学习 AI 代理团队 <a class="header-anchor" href="#推荐路径-学习-ai-代理团队" aria-label="Permalink to &quot;推荐路径：学习 AI 代理团队&quot;">​</a></h3><p>继续学习 <a href="./../../advanced/ai-agents-overview/">AI 代理团队：10 位专家介绍</a>，了解如何使用不同的代理完成专业任务。</p><h3 id="进阶路径-深度定制配置" tabindex="-1">进阶路径：深度定制配置 <a class="header-anchor" href="#进阶路径-深度定制配置" aria-label="Permalink to &quot;进阶路径：深度定制配置&quot;">​</a></h3><p>如果你已经熟悉基础配置，可以跳到 <a href="./../../advanced/advanced-configuration/">配置深度定制：代理与权限管理</a>，学习：</p><ul><li>如何自定义代理的提示词</li><li>如何设置代理的权限和访问范围</li><li>如何创建自定义的代理和 Category</li></ul><h3 id="实战路径-使用-prometheus-规划" tabindex="-1">实战路径：使用 Prometheus 规划 <a class="header-anchor" href="#实战路径-使用-prometheus-规划" aria-label="Permalink to &quot;实战路径：使用 Prometheus 规划&quot;">​</a></h3><p>开始使用 <a href="./../../advanced/prometheus-planning/">Prometheus 规划：面试式需求收集</a>，通过实际的代理协作体验多模型编排的威力。</p><hr><p><strong>开始学习</strong>：从 <a href="./provider-setup/">Provider 配置</a> 开始你的多模型编排之旅吧！</p>`,42)])])}const m=i(r,[["render",s]]);export{u as __pageData,m as default};
